String_to_vector3 = args => {
	let result = new THREE . Vector3 ()
	
	let splits = args . string . split ( ',' )
	
	if ( splits . length > 0 ) result . x = parseFloat ( splits [ 0 ] )
	if ( splits . length > 1 ) result . y = parseFloat ( splits [ 1 ] )
	if ( splits . length > 2 ) result . z = parseFloat ( splits [ 2 ] )
		
	return result
}
Vector3_to_string = args => {
	return args . vector3 . x . toFixed ( 2 ) + ' , ' +
	       args . vector3 . y . toFixed ( 2 ) + ' , ' +
	       args . vector3 . z . toFixed ( 2 ) 
}
 
class Thing                 {
	constructor  ( args ) {
		this . type            = 'thing'
		this . filename        = ''
		this . extension       = ''
		this . name            = 'untitled'
		this . camera_position = camera . position . clone ()
		this . camera_poi      = poi . clone ()
		
		if ( args ) {
			if ( 'type' in args )
				this . type = args . type
			if ( 'filename' in args ) {
				this . filename  = args . filename
				let splits       = this . filename . split ( '.' )
				this . extension = splits . pop () . toLowerCase ()
				this . name      = splits . pop () . split ( '/' ) . pop ()
			}
			if ( 'file_64' in args ) 
				if ( args . file_64 != '' )
					this . open_file_64 ( args )
		}
	}
	open_file_64 ( args ) {}
}
class Model   extends Thing {
	constructor  ( args ) {
		args . type = 'model'
		super ( args )
		
		this . mesh              = null
		this . maping            = null
		this . mapings           = []
		this . material          = null
		this . original_material = null

		model               = this
		models       . push ( model )
		let name_option     = document . createElement ( 'option' )
		name_option  . text = model . name
		model_select . add  ( name_option )		
	}
	open_file_64 ( args ) {
		return new Promise ( ( resolve , reject ) => {
			switch ( this . extension ) {
				case 'glb' : {
					let loader = new THREE . GLTFLoader ()
					loader . model = this
					loader . load ( args . file_64 , glb => {
						this . mesh = glb . scene
						
						this . mesh . make_piece = true
						this . mesh . traverse ( m => {
							if ( 'material' in m ) {
								m . material . bumpMap = m . material . normalMap						
								m . material . normalMap = null
							}
							
							m . make_piece        = true
							m . original_material = m . material
							
							if ( this . material == null ) {
								this . material          = m . material
								this . original_material = this . material
							}
						} )
						resolve ( { thing : this } )
					} )
				} break ;
			}
		} )
	}				
	add_to_scene ( args ) {
		let mesh = this . mesh

		scene . add ( mesh )
		
		let box = new THREE . Box3 () . setFromObject ( mesh )
		let sphere = new THREE . Sphere ()
		box . getBoundingSphere ( sphere )
		let d = 3 * sphere . radius
		if ( d == 0 ) d = 150		
		camera . position . set ( box . min . x + ( box . max . x - box . min . x ) / 2 - d , box . min . y + ( box . max . y - box . min . y ) / 2 + d , box . min . z + ( box . max . z - box . min . z ) / 2 + d )
		poi . set               ( box . min . x + ( box . max . x - box . min . x ) / 2 , box . min . y + ( box . max . y - box . min . y ) / 2 , box . min . z + ( box . max . z - box . min . z ) / 2 )
		
		this . camera_position . copy ( camera . position )
		this . camera_poi . copy ( poi )

		
		this . feature ()


		orbitControls . update ()

		Update_values ()					
		
		Render ()
	}
	feature      ( args ) {
		camera . position . copy ( this . camera_position )
		poi . copy ( this . camera_poi )

		scene . children = []
		scene . add ( this . mesh )
		
	    while ( mapings_select . options . length > 0 ) mapings_select . remove( 0 )
		this . mapings . forEach ( maping => {
			scene . add ( maping . decal_mesh )
			
			let name_option         = document . createElement ( 'option' )
			name_option . text      = maping . name
			mapings_select . add ( name_option )
		} )
		scene . add ( ambientLight )
		scene . add ( directionalLight )
		scene . add ( mouseHelper )						
	}
}
class Texture extends Thing {
	constructor  ( args ) {
		args . type = 'texture'
		super ( args )
		
		//this . image   = null
		//this . texture = null

		textures . push ( this )
		
		let diffuse_map_option     = document . createElement ( 'option' )
		diffuse_map_option . text  = this . name
		diffuse_select . add ( diffuse_map_option )

		let normal_map_option     = document . createElement ( 'option' )
		normal_map_option . text  = this . name
		normal_select . add ( normal_map_option )
	}
	open_file_64 ( args ) {
		return new Promise ( ( resolve , reject ) => {
			let image = document . createElement ( 'img' )
			image . texture = this
			image . addEventListener ( 'load' , function ( event ) {
				let texture = image . texture
				
				texture . image = image
				texture . texture  = new THREE . CanvasTexture ( texture . image )
				
				resolve ( { thing : texture } )
			} )
			image . src = args . file_64
		} )
	}				
}
class Maping                {
	constructor ( args ) {
		this . name            = 'map # ' + ( model . mapings . length + 1 )
		this . object          = null
		this . model_filename  = model . filename
		this . material        = material_select . selectedIndex
		this . position        = new THREE . Vector3 ()
		this . rotation        = new THREE . Vector3 ()
		this . scale           = new THREE . Vector3 ( 1 , 1 , 1 )
		this . diffuse         = diffuse_switch  . checked
		this . diffuse_texture = diffuse_texture
		this . normal          = normal_switch   . checked
		this . normal_texture  = normal_texture
		this . decal_mesh      = decal_mesh
		
		model . maping                  = this
		model . mapings . push ( model . maping )
		let name_option         = document . createElement ( 'option' )
		name_option . text      = model . maping . name
		mapings_select . add ( name_option )

		this . position = String_to_vector3 ( { string : position_text . value } )
		this . rotation = String_to_vector3 ( { string : rotation_text . value } )
		this . scale    = String_to_vector3 ( { string : scale_text    . value } )
	}
}


Allow_drop = event => {
	event . preventDefault ()
}			
Drop       = event => {
  event . preventDefault ()

  if ( event . dataTransfer . items )
	for ( let i = 0 ; i < event . dataTransfer . items . length ; i++ ) {
	  if ( event . dataTransfer . items [ i ] .kind === 'file' ) {
		let file = event . dataTransfer . items [ i ] . getAsFile ()
		Load_file ( { file : file } )
	  }
	}			  
  else
	Load_files ( { files : event . dataTransfer . files } )
}			


Drag_element           = element => {
	tearable_elements . push ( element . parentElement )
}
Model_select_change    = args    => {
	if ( model == null ) return	
	
	let name = model_select . options [ model_select . selectedIndex ] . text
	
	let found = false
	let i = 0
	while ( ! found && i < model_select . options . length ) {
		found = name == models [ i ++ ] . name
	}
	if ( found ) {
		model = models [ -- i ]
		model . feature ()
	}
	else         i = - 1
	
	Update_values ()
	orbitControls . update ()				
	Render ()
}			
Material_select_change = args    => {
	if ( model == null ) return
	
	switch ( material_select . options [ material_select . selectedIndex ] . text . toLowerCase () ) {
		case 'original' : {
			model . mesh . traverse ( m => {							
				m . material = m . original_material
			} )											
			model . material = model . original_material
		} break ;
		case 'gold'     : {
			model . mesh . traverse ( m => {
				m . material = new THREE . MeshPhongMaterial ( {
				  color      :  new THREE . Color ( 'rgb(155,196,30)' ) ,
				  emissive   :  new THREE . Color ( 'rgb(7,3,5)' ) ,
				  specular   :  new THREE . Color ( 'rgb(255,113,0)' ) ,
				  shininess  :  50 ,
				} )										
			} )											
			model . material = new THREE . MeshPhongMaterial ( {
				  color      :  new THREE . Color ( 'rgb(155,196,30)' ) ,
				  emissive   :  new THREE . Color ( 'rgb(7,3,5)' ) ,
				  specular   :  new THREE . Color ( 'rgb(255,113,0)' ) ,
				  shininess  :  50 ,
			} )				
		} break ;
		case 'silver'   : {
			model . mesh . traverse ( m => {
				m . material = new THREE . MeshPhongMaterial ( {
				  color      :  new THREE . Color ( 'rgb(192,192,192)' ) ,
				  emissive   :  new THREE . Color ( 'rgb(7,3,5)' ) ,
				  specular   :  new THREE . Color ( 'rgb(192,192,192)' ) ,
				  shininess  :  50 ,
				} )										
			} )														
			model . material = new THREE . MeshPhongMaterial ( {
				  color      :  new THREE . Color ( 'rgb(192,192,192)' ) ,
				  emissive   :  new THREE . Color ( 'rgb(7,3,5)' ) ,
				  specular   :  new THREE . Color ( 'rgb(192,192,192)' ) ,
				  shininess  :  50 ,
			} )				
		} break ;
	}
	Render ()
}
