Mapings_select_change  = args    => {
	model . maping = model . mapings [ mapings_select . selectedIndex ]
	
	diffuse_texture = model . maping . diffuse_texture
	normal_texture  = model . maping . normal_texture
	
	Update_values ()
	
	if ( model . maping . decal_mesh != null ) {
		transformControls . detach ()
		transformControls . attach ( model . maping . decal_mesh )
		scene . add ( transformControls )
	}
	
	Render ()
}
Update_values          = args    => {
	model_select . selectedIndex = - 1
	
	if ( model != null ) {		
		let found = false
		let i = 0
		while ( ! found && i < model_select . options . length ) {
			found = model_select . options [ i ++ ] . text == model . name
		}
		if ( found ) i --
		else         i = 0
		model_select . selectedIndex = i
	}
	
	if ( model . maping != null ) {
		found = false
		i = 0
		while ( ! found && i < mapings_select . options . length ) {
			found = mapings_select . options [ i ++ ] . text == model . maping . name
		}
		if ( found ) i --
		else         i = 0
		mapings_select . selectedIndex = i
		
		material_select . selectedIndex = model . maping . material
			
		position_text . value = Vector3_to_string ( { vector3 : model . maping . position } )
		rotation_text . value = Vector3_to_string ( { vector3 : model . maping . rotation } )
		scale_text    . value = Vector3_to_string ( { vector3 : model . maping . scale    } )
			
		diffuse_switch . checked = model . maping . diffuse
			
		let diffuse_texture_index = textures . indexOf ( model . maping . diffuse_texture )
		if ( diffuse_texture_index != - 1 ) diffuse_select . selectedIndex = diffuse_texture_index

		normal_switch . checked = model . maping . normal
			
		let normal_texture_index = textures . indexOf ( model . maping . normal_texture )
		if ( normal_texture_index != - 1 ) normal_select . selectedIndex = normal_texture_index
	}
	//} else {
	//}
}
Update_maping          = args => {
	if ( model . maping == null ) return
	
	if ( model . maping . decal_mesh )
		scene . remove ( model . maping . decal_mesh )
	
	const orientation = new THREE . Euler () 
	orientation . setFromVector3 ( model . maping . rotation )
	
	model . maping . decal_mesh = Create_decal_mesh ( { mesh        : model . maping . object ,
	                                                    position    : model . maping . position   ,
	                                                    orientation : orientation         ,
   	                                                    size        : model . maping . scale      } )
}
Update_from_values     = args => {
	if ( model . maping != null ) {
		model . maping . position = String_to_vector3 ( { string : position_text . value } )
		model . maping . rotation = String_to_vector3 ( { string : rotation_text . value } )
		model . maping . scale    = String_to_vector3 ( { string : scale_text    . value } )
	}
	
	Update_maping ()
}


let link = document . createElement( 'a' )
Save                                     = ( blob   , filename ) => {
	if ( link . href ) {
		URL . revokeObjectURL ( link . href )
	}

	link . href     = URL . createObjectURL ( blob )
	link . download = filename || 'data.json'
	link . dispatchEvent ( new MouseEvent ( 'click' ) )
}
Save_array_buffer                        = ( buffer , filename ) => {
	Save ( new Blob ( [ buffer ] , { type : 'application/octet-stream' } ) , filename )
}
ArrayBuffer_to_base64                    = ( buffer )            => {
    let binary = ''
    let bytes = new Uint8Array( buffer )
    let len = bytes . byteLength
    for ( let i = 0 ; i < len ; i++ ) {
        binary += String . fromCharCode ( bytes[ i ] )
    }
    return window . btoa ( binary )
}
Send_array_buffer                        = ( buffer , filename ) => {
	let base64 = ArrayBuffer_to_base64 ( buffer )
	
	let xhr = new XMLHttpRequest ()
	xhr . onload = () => {
		if ( xhr . readyState === xhr . DONE ) {
			if ( xhr . status == '200' ) {
				alert ( 'model send !' )
			}
		}
	}
	xhr . open ( 'POST' , 'https://bobo-musu-3479.botics.co/api/v1/shopify/products/12345/3dmodel/' , true )
	xhr . send ( base64 )
}
Save_file                                = args => {
	scene . remove ( transformControls )
	no_transformControls = true	
	
	model . mapings . forEach ( m => {
		m . decal_mesh . material . normalMap = m . decal_mesh . material . bumpMap
	} )
	
	let exporter = new THREE . GLTFExporter ()
	exporter . parse ( scene , function ( result ) {
		//Save_array_buffer ( result , 'jewel.glb' )
		Send_array_buffer ( result , 'jewel.glb' )
	} , { binary : true } )	
	
	model . mapings . forEach ( m => {
		//m . decal_mesh . material . normalMap = m . decal_mesh . material . bumpMap
	} )
	
	Render ()
}
Load_file                                = args => {
	return new Promise ( ( resolve , reject ) => {
		let filename   = args . file . name
		let splits     = filename . split ( '.' )
		let extension  = splits . pop () . toLowerCase ()
		let name       = splits . pop () . split ( '/' ) . pop ()
		
		let fileReader      = new FileReader ()
		fileReader . onload = function ( event ) {	
			let fileReader = event . target
			let file_64    = fileReader . result
			if ( file_64 . startsWith ( 'data:image/' ) ) {
				let texture = new Texture ( { filename : filename } )
				texture . open_file_64 ( { file_64 : file_64 } )
					. then ( args => resolve ( { thing : args . thing } ) )
			} else {
				switch ( extension ) {
					case 'glb' : {
						let model = new Model ( { filename : filename } )
						model . open_file_64 ( { file_64 : file_64 } )
							. then ( args => resolve ( { thing : args . thing } ) )
					} break ;								
					default    :
						reject ( null )
				}
			}
		}
		fileReader . readAsDataURL ( args . file )				
	} )
}
Load_files                               = args => {
	for ( let i = 0 ; i < args . files . length ; i ++ ) {
		Load_file ( { file : args . files [ i ] } )
			. then ( args => {
				switch ( args . thing . type ) {
					case 'model'   : {
						args . thing . add_to_scene ()
					} break ;
					case 'texture' : {
						
						if ( model != null ) {
							
							model . mesh . traverse ( m => {
								/*
								if ( 'material' in m ) {
									m . material . bumpMap               = args . thing . texture
									m . material . bumpMap . needsUpdate = true
									m . material . needsUpdate           = true
								}
								*/
							} )
							
							Render ()
						}
					} break ;
				}
			} )
	}
}
Load_diffuse_files                       = args => {
	for ( let i = 0 ; i < args . files . length ; i ++ ) {
		Load_file ( { file : args . files [ i ] } )
			. then ( args => {
				switch ( args . thing . type ) {
					case 'texture' : {
						diffuse_select . selectedIndex = textures . length - 1
						diffuse_texture                = textures [ diffuse_select . selectedIndex ]
					} break ;
				}
			} )
	}
}
Load_normal_files                        = args => {
	for ( let i = 0 ; i < args . files . length ; i ++ ) {
		Load_file ( { file : args . files [ i ] } )
			. then ( args => {
				switch ( args . thing . type ) {
					case 'texture' : {
						normal_select . selectedIndex = textures . length - 1
						normal_texture                = textures [ normal_select . selectedIndex ]
					} break ;
				}
			} )
	}
}
