Zoom_in                                  = args => {
	let v = camera . position . clone ()
	v . sub ( poi )
	let d = v . length ()
	v . normalize ()					

	d *= 1.1 ; 
	camera . position . set ( 
		poi . x + d * v . x , 
		poi . y + d * v . y , 
		poi . z + d * v . z )
	
	camera . lookAt ( poi )
	Render ()
}
Zoom_out                                 = args => {
	let v = camera . position . clone ()
	v . sub ( poi )
	let d = v . length ()
	v . normalize ()					

	d /= 1.1 ; 
	camera . position . set ( 
		poi . x + d * v . x , 
		poi . y + d * v . y , 
		poi . z + d * v . z )
	
	camera . lookAt ( poi )
	Render ()
}
Create_decal_mesh                        = args => {
	const geometry = new THREE . DecalGeometry ( args . mesh , args . position , args . orientation , args . size )

	let center = new THREE . Vector3 ()
	geometry . computeBoundingBox ()
	geometry . boundingBox.getCenter ( center )
	geometry . center ()
	//position . copy ( center )
	
	let params = {
		/*
		color               : new THREE . Color ( 'rgb(155,196,30)' ) ,
		emissive            : new THREE . Color ( 'rgb(7,3,5)' ) ,
		specular            : new THREE . Color ( 'rgb(255,113,0)' ) ,
		*/
		//shininess           : 50 ,			
		//specular            : 0x444444 ,
		//normalScale         : new THREE . Vector2 ( 1 , 1 ) ,
		transparent         : true ,
		depthTest           : true ,
		depthWrite          : false ,
		polygonOffset       : true ,
		polygonOffsetFactor : - 4 ,
	}
	
	if ( diffuse_switch . checked ) params . map   	   = diffuse_texture . texture
	if ( normal_switch  . checked ) params . normalMap = normal_texture  . texture

	//const material = new THREE . MeshPhongMaterial ( params )
	//material . color . setHex ( Math . random () * 0xffffff )
	
	const material = model . material . clone ()
	material . transparent         = true 
	material . depthTest           = true 
	material . depthWrite          = false 
	material . polygonOffset       = true 
	material . polygonOffsetFactor = - 4 
	
	if ( diffuse_switch . checked ) material . map     = diffuse_texture . texture
	if ( normal_switch  . checked ) material . bumpMap = normal_texture  . texture
	
	const decal_mesh = new THREE . Mesh ( geometry , material )
	decal_mesh . name = 'decal - ' //+ model . mapings . length
	decal_mesh . maping = model . maping
	decal_mesh . traverse ( d => {
		d . maping = model . maping
	} )
	scene . add ( decal_mesh )
	decal_mesh . position . copy ( args . position )
	model . maping . position . copy ( decal_mesh . position )
	
	transformControls . detach ()
	transformControls . attach ( decal_mesh )
	scene . add ( transformControls )
	no_transformControls = false

	Update_values ()
	Render ()
	
	return decal_mesh
}
Handle_click_on_model                    = args => {
	new Maping ()

	model . maping . object = args . intersection . object
	
	let position = args . intersection . point . clone ()
	
	mouseHelper . position . copy ( position )					
	const n = args . intersection . face . normal . clone ()
	n . transformDirection ( model . mesh . matrixWorld )
	n . multiplyScalar ( 10 )
	n . add ( args . intersection . point )
	mouseHelper . lookAt ( n )
	let orientation = mouseHelper . rotation . clone ()
	orientation . z = model . maping . rotation . z
	model . maping . rotation . copy ( orientation )
	
	let d = camera . position . distanceTo ( model . mesh . position ) / 10
	
	let size = model . maping . scale . clone ()	
	
	model . maping . decal_mesh = Create_decal_mesh ( { mesh        : args . intersection . object ,
	                                            position    : position ,
                                                orientation : orientation ,
	                                            size        : size } )					 
}


Resize      = args  => {
	camera   . aspect = window . innerWidth / window . innerHeight
	camera   . updateProjectionMatrix ()
	renderer . setSize  ( window . innerWidth , window . innerHeight )

	Render ()
}
Keydown     = event => {
	switch ( event . keyCode ) {
		case 27: // escape
			scene . remove ( transformControls )
			no_transformControls = true

			Render ()
		break ;
		case 73: // i
			if ( info_window . style . display == "block" ) info_window . style . display = "hidden"
			else                                            info_window . style . display = "block" 
		break ;
		case 81: // Q
			transformControls . setSpace ( transformControls . space === "local" ? "world" : "local" )
		break;
		case 87: // W
			transformControls . setMode ( "translate" ) 
		break;
		case 69: // E
			transformControls . setMode ( "rotate" )
		break;
		case 82: // R
			transformControls . setMode ( "scale" )
		break;	
		case 84: // T
			if ( tools_window . style . display == "block" ) tools_window . style . display = "hidden"
			else                                             tools_window . style . display = "block" 
		break;	
		case 88: // X
			transformControls . showX = ! transformControls . showX
		break;
		case 89: // Y
			transformControls . showY = ! transformControls . showY
		break;
		case 90: // Z
			transformControls . showZ = ! transformControls . showZ
		break;
		case Key_codes . Page . Down : Zoom_out () ; break ;
		case Key_codes . Page . Up   : Zoom_in  () ; break ;
	}
}
PointerDown = event => {
	if ( event . type === 'touchstart' ) {
		pointer_down_x = event . touches [ 0 ]. clientX
		pointer_down_y = event . touches [ 0 ]. clientY
	} else {
		pointer_down_x = event . x
		pointer_down_y = event . y
	}

	pointer_x     = pointer_down_x
	pointer_y     = pointer_down_y
	
	mouse . x =   ( pointer_x / window . innerWidth  ) * 2 - 1
	mouse . y = - ( pointer_y / window . innerHeight ) * 2 + 1

	pointer_button = event . button
	
	if ( pointer_button != Buttons . left ) return

	if ( event . target != renderer . domElement ) return
	
	raycaster . setFromCamera ( mouse , camera )
	let hitables = []
	if ( ! no_transformControls ) hitables . push ( transformControls )
	//mapings . forEach ( maping => { hitables . push ( maping . decal_mesh ) } )
	hitables . push ( model . mesh )
	let intersection = raycaster . intersectObjects ( hitables , true )
	if ( intersection . length > 0 ) {
		if ( 'make_piece' in intersection [ 0 ] . object ) {
			Handle_click_on_model ( { intersection : intersection [ 0 ] } )
		} else {
			//if ( 'maping' in intersection [ 0 ] . object ) {
			//	mapings_select . selectedIndex = mapings . indexOf ( intersection [ 0 ] . object . maping )
			//	Mapings_select_change ()
			//} else {

				if ( 'type' in intersection [ 0 ] . object ) {
					if ( 'TransformControlsPlane' == intersection [ 0 ] . object . type ) {
						if ( intersection . length > 1 ) {
							if ( 'make_piece' in intersection [ 1 ] . object ) {
								Handle_click_on_model ( { intersection : intersection [ 1 ] } )
							} //else {
								//if ( 'maping' in intersection [ 1 ] . object ) {
								//	mapings_select . selectedIndex = mapings . indexOf ( intersection [ 1 ] . object . maping )
								//	Mapings_select_change ()
								//}
							//} 
						}
					}
				}
				
			//}
		}
	}
}
PointerMove = event => {
	if ( event . type === "touchstart" ) {
		pointer_x = event . touches [ 0 ] . clientX
		pointer_y = event . touches [ 0 ] . clientY
	} else {
		pointer_x = event . x
		pointer_y = event . y
	}
	
	let delta_x   = pointer_x - pointer_x_old
	let delta_y   = pointer_y - pointer_y_old
	
	pointer_x_old = pointer_x
	pointer_y_old = pointer_y
	
	if ( pointer_button != Buttons . left ) return
	
	tearable_elements . forEach ( element => {
								  element . style . left = element . offsetLeft + delta_x
								  element . style . top  = element . offsetTop  + delta_y
	} )
}
PointerUp = event => {
	tearable_elements = []
	
	pointer_button = -1
}
Render      = args  => {
	let delta = clock . getDelta ()
	shader_time += delta * 2

	renderer . render ( scene , camera )			
}
Tick        = args  => {
	//Render ()
}
Main        = args  => {
	document . ondrop     = Drop       
	document . ondragover = Allow_drop 

	file_button            = document . createElement ( 'input' )
	file_button . multiple = true
	file_button . type     = 'file'

	scene               = new THREE . Scene ()
	scene . background  = new THREE . Color ( 0x4080ff )

	poi                 = new THREE . Vector3 ()
	
	camera              = new THREE . PerspectiveCamera ( 25 , window . innerWidth / window . innerHeight , 0.1 , 10000 )
	camera . position . set ( .5 , .5 , - .5 )
	
	ambientLight        = new THREE . AmbientLight ( 0xffffff , .25 )
	scene . add ( ambientLight )

	directionalLight    = new THREE . DirectionalLight ()
	directionalLight . position . set ( 30 , -10 , 30 )
	scene . add ( directionalLight )
				
	renderer            = new THREE . WebGLRenderer ()
	document . body . appendChild (  renderer . domElement )
	
	raycaster           = new THREE . Raycaster ()
	mouse               = new THREE . Vector2   ()
	clock               = new THREE . Clock     ()
	
	mouseHelper         = new THREE . Mesh ( new THREE . BoxGeometry ( 1 , 1 , 10 ) , new THREE . MeshNormalMaterial () )
	mouseHelper . visible = false
	scene . add ( mouseHelper )
	
	position    = new THREE . Vector3 ()
	orientation = new THREE . Euler   ()
	size        = new THREE . Vector3 ( 5 , 5 , 5 )
	
	orbitControls             = new THREE . OrbitControls (  camera ,  renderer . domElement )
	orbitControls . target    = poi
	orbitControls . addEventListener ( 'change' , () => {
		if ( model != null ) {
			//model . camera_position . copy ( camera . position )
			//model . camera_poi . copy ( poi )
		}
		
		Render ()
	} )
	
	transformControls = new THREE . TransformControls ( camera , renderer . domElement )
	transformControls . showZ = ! transformControls . showZ
	transformControls . traverse ( t => {
		t . not_war = true
	} )
	transformControls . addEventListener ( 'change' , Render )
	
	transformControls . addEventListener ( 'dragging-changed', function ( event ) {
		orbitControls . enabled = ! event . value
	} )

	diffuse_texture = new Texture ( { filename : 'fingerprint_bump.png' , file_64: fingerprint_bump_64 } )
	
	normal_texture  = new Texture ( { filename : 'fingerprint_bump.jpg'  , file_64: fingerprint_bump_64  } )
	normal_select . selectedIndex = normal_select . options . length - 1

	let teardrop_model = new Model ( { filename : 'Teardrop.glb' } )
	teardrop_model . open_file_64 ( { file_64 : teardrop_64 } )
		. then ( args => {
			args . thing . mesh . traverse ( m => {
				if ( 'material' in m )
					if ( m . material != null ) {
						m . material . color     = new THREE . Color ( 'rgb(155,196,30)' )
						m . material . emissive  = new THREE . Color ( 'rgb(7,3,5)' )
						m . material . specular  = new THREE . Color ( 'rgb(255,113,0)' )
						m . material . shininess = 50
					}
			} )
			
			args . thing . add_to_scene ()
		} )

	Resize ()

	document . oncontextmenu = event => {
		event . preventDefault ( )
	}
	window   . addEventListener ( 'resize'      , Resize      , false )		
	window   . addEventListener ( 'keydown'     , Keydown     , false )		
	window   . addEventListener ( 'pointerdown' , PointerDown , false )		
	window   . addEventListener ( 'pointermove' , PointerMove , false )		
	window   . addEventListener ( 'pointerup'   , PointerUp   , false )		

	setInterval ( Tick , 1000 / 33 )
}


Main ()